class ESAgent:
    def __init__(self, env=None, weights=None, bias=None):
        if weights is not None:
            self.weights = weights
        else:
            self.weights = np.zeros((env.observation_space.shape[0], 
                                   env.action_space.shape[0]))
        if bias is not None:
            self.bias = bias
        else:
            self.bias = np.zeros(env.action_space.shape[0])

    def reset(self, mode=None):
        pass

    def close(self):
        pass

    def step(self, observation, reward, terminated):
        action = np.matmul(observation, self.weights) + self.bias
        return action

    def train(self, env, scale=0.05, learning_rate=0.2, population=16):
        weight_deltas = [scale * np.random.randn(*self.weights.shape) for _ in range(population)]
        bias_deltas = [scale * np.random.randn(*self.bias.shape) for _ in range(population)]

        agents = [ESAgent(weights=self.weights + weight_delta,
                         bias=self.bias + bias_delta) 
                 for weight_delta, bias_delta in zip(weight_deltas, bias_deltas)]
        rewards = np.array([play_episode(env, agent)[0] for agent in agents])

        std = rewards.std()
        if np.isclose(std, 0):
            coeffs = np.zeros(population)
        else:
            coeffs = (rewards - rewards.mean()) / std

        weight_updates = sum([coeff * weight_delta for coeff, weight_delta in zip(coeffs, weight_deltas)])
        bias_updates = sum([coeff * bias_delta for coeff, bias_delta in zip(coeffs, bias_deltas)])

        self.weights += learning_rate * weight_updates / population
        self.bias += learning_rate * bias_updates / population

